import io.swagger.v3.oas.annotations.media.Schema;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

@Data
@Builder
@AllArgsConstructor
@NoArgsConstructor
public class PageRequest {

    @Schema(description = "Page number (0-based)", example = "0", defaultValue = "0")
    private int page = 0;
    @Schema(description = "Number of items per page", example = "20", defaultValue = "20")
    private int size = 20;
    @Schema(description = "Field to sort by", example = "id", defaultValue = "id")
    private String sortBy = "id";
    @Schema(description = "Sort direction", example = "asc", allowableValues = {"asc", "desc"}, defaultValue = "asc")
    private String sortDirection = "asc";

}

